const htmlStr = typeof $input.first().json === 'string' ? $input.first().json : $input.first().json.data;

// Try to find __NEXT_DATA__ JSON block first (Most robust way to scrape Upwork NextJS app)
let jobsData = [];
try {
  const scriptMatch = htmlStr.match(/<script id="__NEXT_DATA__"[^>]+>([\s\S]*?)<\/script>/);
  if (scriptMatch && scriptMatch[1]) {
    const jsonData = JSON.parse(scriptMatch[1]);
    const searchResults = jsonData?.props?.pageProps?.serverSideData?.searchResults || [];
    if (searchResults.length > 0) jobsData = searchResults;
  }
} catch(e) { /* fallback */ }

// Fallback: Extremely generic RegEx extraction for Job titles and links just in case
if (jobsData.length === 0) {
  const titleRegex = /<h3 class="job-tile-title">.*?<a href="([^"]+)".*?>([\s\S]*?)<\/a>.*?<\/h3>/gi;
  const descRegex = /<span data-test="job-description-text">([\s\S]*?)<\/span>/gi;
  let matchTitle;
  let matchDesc;
  while ((matchTitle = titleRegex.exec(htmlStr)) !== null) {
    matchDesc = descRegex.exec(htmlStr);
    jobsData.push({
      url: 'https://www.upwork.com' + matchTitle[1],
      title: matchTitle[2].replace(/<[^>]*>?/gm, '').trim(),
      description: matchDesc ? matchDesc[1].replace(/<[^>]*>?/gm, '').trim() : '',
    });
  }
}

// Mapping to standard format for the rest of workflow
const formattedJobs = jobsData.map(job => {
  return { json: {
    title: job.title || job.titleText,
    link: job.url || job.ciphertext ? `https://www.upwork.com/jobs/~${job.ciphertext}` : '',
    description: job.description || job.snippet,
    isPaymentVerified: job.client?.paymentVerificationStatus === 1 || false
  }};
});

return formattedJobs.length > 0 ? formattedJobs : [{ json: { noResults: true, title: '' } }];

const keywords = ['laravel', 'php', 'api', 'payment', 'bug fix', 'bug fixing', 'rest api', 'mysql'];
const blacklist = ['wordpress', 'shopify', 'wix', '.net', 'react native', 'flutter', 'django'];

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenJobs) staticData.seenJobs = {};

const now = Date.now();
// Clean entries older than 7 days
for (const [id, ts] of Object.entries(staticData.seenJobs)) {
  if (now - ts > 7*24*60*60*1000) delete staticData.seenJobs[id];
}

const results = [];
for (const item of $input.all()) {
  if (item.json.noResults) continue;

  const title = (item.json.title || '').toLowerCase();
  const desc = (item.json.description || '').toLowerCase();
  const link = item.json.link || '';
  const combined = title + ' ' + desc;
  const jobId = link || title;

  if (!jobId || staticData.seenJobs[jobId]) continue;

  const matched = keywords.filter(kw => combined.includes(kw));
  if (matched.length === 0) continue;

  const blocked = blacklist.some(kw => combined.includes(kw));
  if (blocked) continue;

  staticData.seenJobs[jobId] = now;

  const sysPrompt = 'You are an expert PHP/Laravel developer. Write a compelling, concise Upwork proposal...';
  const userPrompt = 'JOB TITLE: ' + (item.json.title) + '\n\nDESCRIPTION:\n' + (item.json.description) + '\n\nWrite the proposal now:';

  results.push({
    json: {
      ...item.json,
      matchedKeywords: matched,
      qualityScore: matched.length,
      openaiBody: JSON.stringify({ model: 'gpt-4o-mini', messages: [{ role: 'system', content: sysPrompt }, { role: 'user', content: userPrompt }], temperature: 0.7, max_tokens: 600 })
    }
  });
}

return results.length > 0 ? results : [{ json: { noResults: true, title: '' } }];

const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  const proposal = items[i].json.choices?.[0]?.message?.content || 'Failed to generate proposal';
  const job = $('Filter and Prepare AI').all()[i]?.json || {};
  const title = job.title || 'Unknown Job';
  const link = job.link || '#';
  const matched = (job.matchedKeywords || []).join(', ');

  const subject = '🚀 New Upwork Job: ' + title;
  const body = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><div style="background:linear-gradient(135deg,#667eea,#764ba2);padding:20px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#fff;margin:0;font-size:22px">🎯 Scraped Job Match!</h1></div><div style="background:#f8f9fa;padding:20px;border:1px solid #e9ecef"><h2 style="color:#2d3748;margin-top:0">' + title + '</h2><p style="margin-top:10px"><strong>Matched Skills:</strong> ' + matched + '</p><div style="margin:15px 0"><a href="' + link + '" style="display:inline-block;background:#4299e1;color:#fff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:bold">🔗 View Job on Upwork</a></div></div><div style="background:#fff;padding:20px;border:1px solid #e9ecef;border-top:none"><h3 style="color:#2d3748;border-bottom:2px solid #667eea;padding-bottom:8px">📝 AI-Generated Proposal</h3><div style="background:#f7fafc;padding:15px;border-radius:8px;border-left:4px solid #667eea;white-space:pre-wrap;line-height:1.6">' + proposal + '</div></div><div style="background:#2d3748;color:#a0aec0;padding:15px;border-radius:0 0 12px 12px;text-align:center;font-size:12px"><p>Upwork Auto Job Hunter (ScraperAPI) • n8n</p></div></div>';

  results.push({ json: { subject, body, title, link, proposal } });
}
return results;
